#include <SPI.h>
#include <Adafruit_MAX31855.h>

extern int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float* intg,float* lastE);

Adafruit_MAX31855 tc(4);
const int SSR_PIN=9,SOL_PIN=7,PRES_PIN=A0;
const float KP=2.0f,KI=0.05f,KD=2.0f;
const float VAC_SP=0.85f;
float intg=0,lastE=0;
float prev_temp=25.0f;

struct Seg{float temp;float ramp;unsigned long dwell_s;};
Seg profile[]={{120,2,3600},{180,2,7200},{60,-3,0}};
const int N_SEG=3;
int seg=0;float seg_sp=25;unsigned long dwell_start=0;bool in_dwell=false;

// === Thermocouple ===
float tc_read(){double v=tc.readCelsius();return isnan(v)?-999.0f:(float)v;}

// === SSR Actuator ===
void ssr_init(){pinMode(SSR_PIN,OUTPUT);analogWrite(SSR_PIN,0);}
void ssr_set(int p){analogWrite(SSR_PIN,constrain(p,0,255));}

// === Pressure ===
void pressure_init(){pinMode(PRES_PIN,INPUT);}
float pressure_read(){return analogRead(PRES_PIN)*10.0f/1023.0f;}
void vacuum_ctrl(float p_bar){pinMode(SOL_PIN,OUTPUT);digitalWrite(SOL_PIN,(p_bar<VAC_SP)?HIGH:LOW);}

// === Ramp Profile ===
void profile_advance(float pv,unsigned long now,float dt_s){
  if(seg>=N_SEG)return;
  if(!in_dwell){seg_sp+=profile[seg].ramp*dt_s/60.0f;bool reached=(profile[seg].ramp>=0)?(seg_sp>=profile[seg].temp):(seg_sp<=profile[seg].temp);if(reached){seg_sp=profile[seg].temp;in_dwell=true;dwell_start=now;}}
  else if(now-dwell_start>profile[seg].dwell_s*1000UL){seg++;in_dwell=false;}}

// === Exotherm Runaway ===
bool exotherm_check(float pv,float dt_s){float rate=(pv-prev_temp)/dt_s*60.0f;prev_temp=pv;if(rate>5.0f){Serial.println("WARN:EXOTHERM");return true;}return false;}

// === Fault Handler ===
bool fault_check(float t){if(t>200.0f||t<-100.0f){ssr_set(0);Serial.println("FAULT:TC");return true;}return false;}

void setup(){
  Serial.begin(115200);tc.begin();
  ssr_init();pressure_init();
  Serial.println("t_s,sp,pv,pres_bar,pwm,seg");
}

unsigned long lastMs=0;
void loop(){
  unsigned long now=millis();
  float dt=(now-lastMs)/1000.0f;
  if(dt<0.5f)return;lastMs=now;
  float pv=tc_read(),pres=pressure_read();
  if(fault_check(pv))return;
  bool hold=exotherm_check(pv,dt);
  if(!hold)profile_advance(pv,now,dt);
  int pwm=pid_heater_control(seg_sp,pv,dt,KP,KI,KD,&intg,&lastE);
  ssr_set(pwm);
  vacuum_ctrl(pres);
  Serial.print(now/1000);Serial.print(',');Serial.print(seg_sp,0);Serial.print(',');Serial.print(pv,1);Serial.print(',');Serial.print(pres,2);Serial.print(',');Serial.print(pwm);Serial.print(',');Serial.println(seg);
}
